import {
  Box,
  Button,
  Flex,
  Text,
  Table,
  Thead,
  Tbody,
  Tr,
  Th,
  Td,
  Image,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";

import TeacherNavTop from "./TeacherNavTop";
import Pagination from "../Adminitems/Pagination";

import convertDateFormat, {
  deleteProduct,
  getvideo,
} from "../../Redux/TeacherReducer/action";

const GetTeacherVideos = () => {
  const store = useSelector((store) => store.TeacherReducer.videos);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [page, setPage] = useState(1);
  const limit = 4;

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    dispatch(getvideo(page, limit, user.userId));
  }, [page]);

  const handleDelete = (id, title) => {
    dispatch(deleteProduct(id));
    alert(`${title} deleted`);
  };

  return (
    <>
      <TeacherNavTop />

      <Box bg="#f7f9fa" minH="100vh" p={6}>
        <Box maxW="1100px" mx="auto">
          
          {/* HEADER */}
          <Flex justify="space-between" align="center" mb={6}>
            <Text fontSize="2xl" fontWeight="bold">
              Your Videos
            </Text>

            <Button
              bg="#A435F0"
              color="white"
              _hover={{ bg: "#8710d8" }}
              onClick={() => navigate("/Teacher/add")}
            >
              Add Video
            </Button>
          </Flex>

          {/* TABLE */}
          <Box bg="white" borderRadius="lg" boxShadow="sm" overflow="hidden">
            <Table>
              <Thead bg="#f1f3f5">
                <Tr>
                  <Th>Video</Th>
                  <Th>Views</Th>
                  <Th>Date</Th>
                  <Th>Action</Th>
                </Tr>
              </Thead>

              <Tbody>
                {store?.map((el) => (
                  <Tr key={el._id} _hover={{ bg: "#f7f9fa" }}>
                    
                    {/* VIDEO */}
                    <Td>
                      <Flex align="center" gap={3}>
                        <Image
                          src={el.img}
                          boxSize="60px"
                          borderRadius="md"
                          objectFit="cover"
                        />
                        <Box>
                          <Text fontWeight="bold">{el.title}</Text>
                          <Text fontSize="xs" color="gray.500">
                            {el.description?.slice(0, 40)}...
                          </Text>
                        </Box>
                      </Flex>
                    </Td>

                    <Td>{el.views}</Td>
                    <Td>{convertDateFormat(el.createdAt)}</Td>

                    {/* ACTION */}
                    <Td>
                      <Flex gap={2}>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => window.open(el.link, "_blank")}
                        >
                          View
                        </Button>

                        <Button
                          size="sm"
                          colorScheme="red"
                          onClick={() => handleDelete(el._id, el.title)}
                        >
                          Delete
                        </Button>
                      </Flex>
                    </Td>
                  </Tr>
                ))}
              </Tbody>
            </Table>
          </Box>

          {/* PAGINATION */}
          <Flex justify="center" mt={6} gap={2}>
            <Button
              onClick={() => setPage((p) => p - 1)}
              isDisabled={page === 1}
            >
              Prev
            </Button>

            <Pagination
              totalCount={Math.ceil(store.length / limit)}
              current_page={page}
              handlePageChange={setPage}
            />

            <Button onClick={() => setPage((p) => p + 1)}>
              Next
            </Button>
          </Flex>
        </Box>
      </Box>
    </>
  );
};

export default GetTeacherVideos;
